class DarkMode{constructor(){this.isDark = localStorage.getItem('darkMode')=== 'true';this.init();}init(){if(this.isDark){this.enable();}this.addToggleButton();this.injectStyles();}addToggleButton(){if(document.getElementById('dark-mode-toggle'))return;const toggle = document.createElement('li');toggle.className = 'nav-item';toggle.innerHTML = ` <a class="nav-link" href="#" id="dark-mode-toggle" title="تبديل الوضع الداكن"> <i class="fas fa-moon"></i> </a> `;const navbar = document.querySelector('.navbar-nav.ml-auto');if(navbar){navbar.insertBefore(toggle,navbar.firstChild);}document.getElementById('dark-mode-toggle').addEventListener('click',(e)=>{e.preventDefault();this.toggle();});}injectStyles(){if(document.getElementById('dark-mode-styles'))return;const style = document.createElement('style');style.id = 'dark-mode-styles';style.textContent = ` body.dark-mode{background-color:#1a1a2e;color:#e0e0e0;}.dark-mode .main-header{background:linear-gradient(135deg,#2d3561 0%,#1f1f3a 100%)!important;border-bottom:1px solid #3a3a5a;}.dark-mode .main-header .nav-link{color:#e0e0e0 !important;}.dark-mode .main-sidebar{background-color:#16213e !important;}.dark-mode .nav-sidebar .nav-link{color:#b0b0c8 !important;}.dark-mode .nav-sidebar .nav-link:hover,.dark-mode .nav-sidebar .nav-link.active{background-color:#1f2f4d !important;color:#ffffff !important;}.dark-mode .content-wrapper{background-color:#1a1a2e;}.dark-mode .card{background-color:#2d2d44;border-color:#3a3a5a;color:#e0e0e0;}.dark-mode .card-header{background:linear-gradient(135deg,#2d3561 0%,#1f2841 100%);border-bottom-color:#3a3a5a;color:#ffffff;}.dark-mode .table{color:#e0e0e0;}.dark-mode .table thead th{background:linear-gradient(135deg,#2d3561 0%,#1f2841 100%);color:#ffffff;border-color:#3a3a5a;}.dark-mode .table tbody tr{border-color:#3a3a5a;}.dark-mode .table tbody tr:hover{background-color:#2a2a42;}.dark-mode .form-control{background-color:#2a2a42;border-color:#3a3a5a;color:#e0e0e0;}.dark-mode .form-control:focus{background-color:#323252;border-color:#667eea;color:#ffffff;}.dark-mode .form-control::placeholder{color:#8a8a9a;}.dark-mode .input-group-text{background-color:#2d2d44;border-color:#3a3a5a;color:#e0e0e0;}.dark-mode .btn-primary{background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);border:none;}.dark-mode .btn-secondary{background-color:#3a3a5a;border-color:#4a4a6a;color:#e0e0e0;}.dark-mode .btn-outline-primary{color:#667eea;border-color:#667eea;}.dark-mode .btn-outline-primary:hover{background-color:#667eea;color:white;}.dark-mode .modal-content{background-color:#2d2d44;color:#e0e0e0;}.dark-mode .modal-header{border-bottom-color:#3a3a5a;}.dark-mode .modal-footer{border-top-color:#3a3a5a;}.dark-mode .close{color:#e0e0e0;}.dark-mode .breadcrumb{background-color:#2a2a42;}.dark-mode .breadcrumb-item.active{color:#b0b0c8;}.dark-mode .pagination .page-link{background-color:#2a2a42;border-color:#3a3a5a;color:#e0e0e0;}.dark-mode .pagination .page-link:hover{background-color:#3a3a5a;color:#ffffff;}.dark-mode .pagination .page-item.active .page-link{background-color:#667eea;border-color:#667eea;}.dark-mode .main-footer{background-color:#16213e;border-top:1px solid #3a3a5a;color:#b0b0c8;}.dark-mode .select2-container--bootstrap4 .select2-selection{background-color:#2a2a42;border-color:#3a3a5a;color:#e0e0e0;}.dark-mode .select2-container--bootstrap4 .select2-dropdown{background-color:#2d2d44;border-color:#3a3a5a;}.dark-mode .select2-container--bootstrap4 .select2-results__option{color:#e0e0e0;}.dark-mode .select2-container--bootstrap4 .select2-results__option--highlighted{background-color:#3a3a5a;}.dark-mode .toast{background-color:#2d2d44;border-right-color:currentColor;}.dark-mode .toast-title{color:#ffffff;}.dark-mode .toast-message{color:#b0b0c8;}body,.main-header,.main-sidebar,.content-wrapper,.card,.form-control,.btn{transition:background-color 0.3s ease,color 0.3s ease,border-color 0.3s ease;}#dark-mode-toggle i{transition:transform 0.3s ease;}body.dark-mode #dark-mode-toggle i{transform:rotate(180deg);}`;document.head.appendChild(style);}enable(){document.body.classList.add('dark-mode');this.isDark = true;localStorage.setItem('darkMode','true');const icon = document.querySelector('#dark-mode-toggle i');if(icon){icon.className = 'fas fa-sun';}}disable(){document.body.classList.remove('dark-mode');this.isDark = false;localStorage.setItem('darkMode','false');const icon = document.querySelector('#dark-mode-toggle i');if(icon){icon.className = 'fas fa-moon';}}toggle(){if(this.isDark){this.disable();notify.info('تم تفعيل الوضع النهاري');}else{this.enable();notify.info('تم تفعيل الوضع الداكن');}}}window.darkMode = new DarkMode();